// ─── Error boundary (catches tab render crashes, shows message not blank page) ─
class TabErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { err: null } }
  static getDerivedStateFromError(err) { return { err } }
  componentDidCatch(err, info) { console.error('[TabErrorBoundary]', err, info) }
  render() {
    if (this.state.err) {
      return (
        <div style={{padding:'32px 24px',color:'#C2452D',fontFamily:"'DM Sans',system-ui,sans-serif",fontSize:13}}>
          <strong>Tab render error:</strong> {String(this.state.err?.message || this.state.err)}
          <br/><button onClick={()=>this.setState({err:null})} style={{marginTop:8,padding:'4px 12px',cursor:'pointer'}}>Retry</button>
        </div>
      )
    }
    return this.props.children
  }
}

