// ─── Constants ───────────────────────────────────────────────────────────────
const BASE_DATE = new Date('2024-06-01T00:00:00Z')
const GA4_START = 382  // 2025-06-16
const GA4_END   = 767  // 2026-07-08
const MIG_START = 245  // 2025-02-01
const MIG_END   = 303  // 2025-03-31

// ─── Date utilities ──────────────────────────────────────────────────────────
function dayOffset(dateStr) {
  return Math.round((new Date(dateStr + 'T00:00:00Z') - BASE_DATE) / 86400000)
}
function offsetToDate(o) {
  const d = new Date(BASE_DATE.getTime() + o * 86400000)
  return d.toISOString().slice(0,10)
}
function isoWeekOf(dateStr) {
  const d = new Date(dateStr + 'T00:00:00Z')
  const thu = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate() + 4 - (d.getUTCDay()||7)))
  const jan4 = new Date(Date.UTC(thu.getUTCFullYear(), 0, 4))
  const startW = new Date(Date.UTC(jan4.getUTCFullYear(), jan4.getUTCMonth(), jan4.getUTCDate() - (jan4.getUTCDay()||7) + 1))
  const wn = Math.round((thu - startW) / 604800000) + 1
  return { week: wn, year: thu.getUTCFullYear() }
}
function shiftMonth(dateStr, months) {
  const d = new Date(dateStr + 'T00:00:00Z')
  const y = d.getUTCFullYear(), m = d.getUTCMonth()
  const newM = m + months
  const target = new Date(Date.UTC(y + Math.floor(newM/12), ((newM%12)+12)%12, 1))
  const lastDay = new Date(Date.UTC(target.getUTCFullYear(), target.getUTCMonth()+1, 0)).getUTCDate()
  return new Date(Date.UTC(target.getUTCFullYear(), target.getUTCMonth(), Math.min(d.getUTCDate(), lastDay))).toISOString().slice(0,10)
}
function fmt2Date(s) {
  const d = new Date(s + 'T00:00:00Z')
  return d.getUTCDate()+' '+['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][d.getUTCMonth()]+' '+String(d.getUTCFullYear()).slice(2)
}

// ─── Data aggregators ────────────────────────────────────────────────────────
function sumSD(s, e) {
  let vs=0,vvs=0,vpf=0,vp=0,vtx=0,vr=0
  for (let o=dayOffset(s); o<=dayOffset(e); o++) {
    const d=SD[o]; if(!d) continue
    vs+=d[0]; vvs+=d[1]; vpf+=d[2]; vp+=d[3]; vtx+=d[4]; vr+=d[5]
  }
  return {s:vs,vs:vvs,pf:vpf,p:vp,tx:vtx,r:vr}
}

// ─── Ops aggregator: uses per-airport daily AP_OPS (touch attribution) ────────
// Post-OPS_S (≥ offset 304, Apr 2025+): AP_OPS per-airport daily data (accurate, ~5% below
//   dispatch total due to multi-leg touch attribution — D2 rule).
// Pre-OPS_S (< offset 304, e.g. Feb–Mar 2025 migration): falls back to SOD_RAW subtraction.
//   These months are flagged as backfill, never compared, never used in KPI cards.
const _opsCache = {}
function _getOpsMap(cd) {
  if (_opsCache[cd]) return _opsCache[cd]
  const raw = _AP_OPS_RAW[cd]; if (!raw) { _opsCache[cd]={}; return {} }
  const m = {}
  raw.split('|').forEach(seg => { const p=seg.split(':'); m[+p[0]]=[+p[1]||0,+p[2]||0,+p[3]||0] })
  _opsCache[cd] = m; return m
}
function sumSOD(s, e) {
  const fo=dayOffset(s), to=dayOffset(e)
  // Pre-OPS_S: use SOD_RAW (still embedded) for the migration backfill visual
  if (to < 304) {
    const sodEnd = SOD[to], sodPrev = SOD[fo-1]
    if (sodEnd && sodPrev) {
      return { b: Math.abs(sodEnd[0]-sodPrev[0]), c: Math.abs(sodEnd[1]-sodPrev[1]), tn: Math.abs(sodEnd[2]-sodPrev[2]) }
    }
    return {b:0,c:0,tn:0}
  }
  // Post-OPS_S: sum per-airport AP_OPS daily data
  const lo=Math.max(fo,304), hi=to
  let vb=0,vc=0,vtn=0
  for (const cd of Object.keys(_AP_OPS_RAW)) {
    const m=_getOpsMap(cd)
    for (let o=lo; o<=hi; o++) { const d=m[o]; if(!d) continue; vb+=d[0]; vc+=d[1]; vtn+=d[2] }
  }
  return {b:vb,c:vc,tn:vtn}
}
function rangeHasGA4(s,e){ const so=dayOffset(s),eo=dayOffset(e); return so<=GA4_END&&eo>=GA4_START }
function rangeHasMig(s,e){ const so=dayOffset(s),eo=dayOffset(e); return so<=MIG_END&&eo>=MIG_START }

// ─── Formatters ──────────────────────────────────────────────────────────────
function fmtK(n) {
  if(n==null||isNaN(n)) return '—'
  const a=Math.abs(n),sg=n<0?'-':''
  if(a>=1e6) return sg+'£'+(a/1e6).toFixed(2)+'M'  // won't be used for non-£
  if(a>=1e4) return sg+Math.round(a/1e3)+'K'
  if(a>=1e3) return sg+(a/1e3).toFixed(1)+'K'
  return sg+Math.round(a).toLocaleString('en-GB')
}
function fmtNum(n) {
  if(n==null||isNaN(n)) return '—'
  const a=Math.abs(n),sg=n<0?'-':''
  if(a>=1e6) return sg+(a/1e6).toFixed(1)+'M'
  if(a>=1e4) return sg+Math.round(a/1e3)+'K'
  if(a>=1e3) return sg+(a/1e3).toFixed(1)+'K'
  return sg+Math.round(a).toLocaleString('en-GB')
}
function fmtGBP(n) {
  if(n==null||isNaN(n)) return '—'
  const a=Math.abs(n),sg=n<0?'-':''
  if(a>=1e6) return sg+'£'+(a/1e6).toFixed(2)+'M'
  if(a>=1e3) return sg+'£'+Math.round(a/1e3)+'K'
  return sg+'£'+Math.round(a).toLocaleString('en-GB')
}
function fmtPct(n,dp=2){ return n==null||isNaN(n)?'—':n.toFixed(dp)+'%' }
function pctDelta(cur,prv){ return prv&&prv!==0?((cur-prv)/Math.abs(prv)*100):null }
function niceStep(v){ const m=Math.pow(10,Math.floor(Math.log10(Math.max(v,1)))); for(const f of[1,2,2.5,5,10]){if(v/m<=f)return m*f}; return m*10 }

// ─── Range computation ───────────────────────────────────────────────────────
function getRange(tf, cStart, cEnd) {
  const t='2026-07-08'
  switch(tf){
    case 'latest_day':   return {s:t, e:t}
    case 'prior_day':    return {s:'2026-07-07', e:'2026-07-07'}
    case 'past7':        return {s:'2026-07-02', e:t}
    case 'past14':       return {s:'2026-06-25', e:t}
    case 'past28':       return {s:'2026-06-11', e:t}
    case 'past90':       return {s:'2026-04-09', e:t}
    case 'this_week':    return {s:'2026-07-06', e:t}
    case 'last_week':    return {s:'2026-06-29', e:'2026-07-05'}
    case 'this_month':   return {s:'2026-07-01', e:t}
    case 'last_month':   return {s:'2026-06-01', e:'2026-06-30'}
    case 'this_quarter': return {s:'2026-07-01', e:t}
    case 'last_quarter': return {s:'2026-04-01', e:'2026-06-30'}
    case 'past12m':      return {s:'2025-07-09', e:t}
    case 'custom':       return {s:cStart, e:cEnd}
    default:             return {s:'2026-06-29', e:'2026-07-05'}
  }
}
function getCmpRange(cmpType, s, e, tf) {
  if(cmpType==='none') return null
  const sd=new Date(s+'T00:00:00Z'), ed=new Date(e+'T00:00:00Z')
  const durMs=ed-sd
  const calPresets=['this_month','last_month','this_quarter','last_quarter','past12m']
  if(cmpType==='prev'){
    const ce=new Date(sd.getTime()-86400000), cs=new Date(ce.getTime()-durMs)
    return {s:cs.toISOString().slice(0,10), e:ce.toISOString().slice(0,10), label:'previous period'}
  }
  if(cmpType==='wow'){
    const cs=new Date(sd.getTime()-7*86400000), ce=new Date(ed.getTime()-7*86400000)
    return {s:cs.toISOString().slice(0,10), e:ce.toISOString().slice(0,10), label:'WoW (−7d)'}
  }
  if(cmpType==='mom'){
    return {s:shiftMonth(s,-1), e:shiftMonth(e,-1), label:'MoM (−1 month)'}
  }
  if(cmpType==='qoq'){
    return {s:shiftMonth(s,-3), e:shiftMonth(e,-3), label:'QoQ (−3 months)'}
  }
  if(cmpType==='yoy'){
    if(calPresets.includes(tf)){
      return {s:shiftMonth(s,-12), e:shiftMonth(e,-12), label:'last year (calendar, −12 months)'}
    } else {
      const cs=new Date(sd.getTime()-364*86400000), ce=new Date(ed.getTime()-364*86400000)
      const {week:wn}=isoWeekOf(cs.toISOString().slice(0,10))
      return {s:cs.toISOString().slice(0,10), e:ce.toISOString().slice(0,10), label:`last year (weekday-aligned, −364d = same ISO week)`}
    }
  }
  return null
}

// ─── Delta chip component ────────────────────────────────────────────────────
function DeltaChip({ cur, prv, valid, isPP=false }) {
  if (!valid || prv==null || prv===0) {
    return <span className="kpi-badge neutral">— no basis</span>
  }
  let text, up
  if (isPP) {
    const d=cur-prv; up=d>=0; text=(d>=0?'+':'')+d.toFixed(2)+'pp'
  } else {
    const d=pctDelta(cur,prv); up=d>=0; text=(d>=0?'+':'')+d.toFixed(1)+'%'
  }
  return (
    <span className={`kpi-badge ${up?'up':'down'}`}>
      {up?'▲':'▼'} {text}
    </span>
  )
}

// ─── KPI Card component ──────────────────────────────────────────────────────
function KpiCard({ src, label, value, was, delta, note }) {
  return (
    <div className="kpi-card" style={{ position:'relative', display:'flex', flexDirection:'column', gap:2, minWidth:0 }}>
      {/* Source tag — top right */}
      <div style={{ fontSize:9, fontWeight:700, letterSpacing:'.07em', textTransform:'uppercase',
        color:'var(--subtext)', marginBottom:4, opacity:0.7 }}>{src}</div>
      {/* Label */}
      <div className="kpi-label" style={{ marginBottom:6 }}>{label}</div>
      {/* Value */}
      <div className="kpi-value" style={{ fontSize:28, marginBottom:6 }}>{value}</div>
      {/* Was (comparison) */}
      {was && (
        <div style={{ fontSize:11, color:'var(--subtext)', marginBottom:4 }}>
          was <strong style={{ color:'var(--navy)' }}>{was}</strong>
        </div>
      )}
      {/* Delta chip */}
      {delta}
      {/* Sub note */}
      {note && <div className="kpi-sub" style={{ marginTop:4, lineHeight:1.45 }}>{note}</div>}
    </div>
  )
}

// ─── Chart 1: Demand & bookings week by week (inline SVG) ───────────────────
function Chart1({ width }) {
  const W = width || 900, H = 280
  const PAD = { l:58, r:58, t:22, b:36 }
  const plotW = W-PAD.l-PAD.r, plotH = H-PAD.t-PAD.b

  // Aggregate by ISO week
  const weekMap = {}
  for (let o=GA4_START; o<=GA4_END; o++) {
    if(!SD[o]) continue
    const ds=offsetToDate(o)
    const {week:wn,year:wy}=isoWeekOf(ds)
    const k=`${wy}-${String(wn).padStart(2,'0')}`
    if(!weekMap[k]) weekMap[k]={s:0,tx:0,days:0,wn,wy}
    weekMap[k].s+=SD[o][0]; weekMap[k].tx+=SD[o][4]; weekMap[k].days++
  }
  const keys=Object.keys(weekMap).sort()
  const sVals=keys.map(k=>weekMap[k].s)
  const txVals=keys.map(k=>weekMap[k].tx)
  const partials=keys.map(k=>weekMap[k].days<7)
  const labels=keys.map(k=>{ const w=weekMap[k]; return String(w.wy).slice(2)+'W'+String(w.wn).padStart(2,'0') })
  const n=keys.length

  const maxS=Math.max(...sVals)*1.15||1
  const maxTx=Math.max(...txVals)*1.25||1
  const sStep=niceStep(maxS/4)
  const txStep=niceStep(maxTx/4)
  const groupW=plotW/n
  const barW=Math.max(2,Math.min(groupW*0.72,22))

  const elems=[]

  // Grid + Y labels
  for(let i=0;i<=4;i++){
    const y=PAD.t+plotH-(i/4)*plotH
    elems.push(<line key={'g'+i} x1={PAD.l} y1={y} x2={W-PAD.r} y2={y} stroke={T.line} strokeWidth={0.7}/>)
    elems.push(<text key={'yl'+i} x={PAD.l-6} y={y+3.5} textAnchor="end" fontSize={9} fill={T.inkSoft}>{fmtNum(Math.round(sStep*i))}</text>)
    elems.push(<text key={'yr'+i} x={W-PAD.r+6} y={y+3.5} textAnchor="start" fontSize={9} fill={T.prior}>{fmtNum(Math.round(txStep*i))}</text>)
  }

  // Bars
  keys.forEach((k,i)=>{
    const cx=PAD.l+i*groupW+groupW/2
    const bh=(sVals[i]/maxS)*plotH
    elems.push(
      <rect key={'b'+i} x={cx-barW/2} y={PAD.t+plotH-bh} width={barW} height={bh} rx={2}
        fill={T.leaf} opacity={partials[i]?0.45:1}>
        <title>{labels[i]}: searches={fmtNum(sVals[i])}, tx={txVals[i]}</title>
      </rect>
    )
  })

  // Tx line path
  const pts=txVals.map((v,i)=>({x:PAD.l+i*groupW+groupW/2, y:PAD.t+plotH-(v/maxTx)*plotH, partial:partials[i],v}))
  const d='M'+pts.map(p=>`${p.x.toFixed(1)},${p.y.toFixed(1)}`).join('L')
  elems.push(<path key="txline" d={d} fill="none" stroke={T.prior} strokeWidth={1.8} strokeLinejoin="round"/>)

  // Points
  pts.forEach((p,i)=>{
    if(p.partial){
      elems.push(<circle key={'pt'+i} cx={p.x.toFixed(1)} cy={p.y.toFixed(1)} r={4} fill="white" stroke={T.prior} strokeWidth={1.5}><title>{labels[i]}: tx={p.v}</title></circle>)
    } else {
      elems.push(<circle key={'pt'+i} cx={p.x.toFixed(1)} cy={p.y.toFixed(1)} r={3} fill={T.prior}><title>{labels[i]}: tx={p.v}</title></circle>)
    }
  })

  // X labels — every ~4th
  const step=Math.max(1,Math.round(n/18))
  keys.forEach((k,i)=>{
    if(i%step!==0) return
    const cx=PAD.l+i*groupW+groupW/2
    elems.push(<text key={'xl'+i} x={cx.toFixed(1)} y={H-PAD.b+14} textAnchor="middle" fontSize={9} fill={T.inkSoft}>{labels[i]}</text>)
  })

  // Y axis labels
  elems.push(<text key="yla" x={PAD.l-40} y={PAD.t+plotH/2} textAnchor="middle" fontSize={9} fill={T.leaf} transform={`rotate(-90,${PAD.l-40},${PAD.t+plotH/2})`}>Searches</text>)
  elems.push(<text key="yra" x={W-PAD.r+42} y={PAD.t+plotH/2} textAnchor="middle" fontSize={9} fill={T.prior} transform={`rotate(90,${W-PAD.r+42},${PAD.t+plotH/2})`}>Transactions</text>)

  return (
    <svg width={W} height={H} style={{display:'block',fontFamily:"'DM Sans',system-ui,sans-serif"}}>
      {elems}
    </svg>
  )
}

// ─── Chart 2: Operations month by month ─────────────────────────────────────
function Chart2({ width }) {
  const W=width||900, H=300
  const PAD={l:62,r:72,t:32,b:36}
  const plotW=W-PAD.l-PAD.r, plotH=H-PAD.t-PAD.b

  // Months Jan 2025 .. Jul 2026
  const months=[]
  for(let y=2025;y<=2026;y++){
    const mEnd=y===2025?12:7
    for(let m=1;m<=mEnd;m++) months.push({y,m})
  }
  const n=months.length

  const isBackfill=(y,m)=>y===2025&&(m===2||m===3)
  const isCurrent=(y,m)=>y===2026&&m===7

  const netB=[], netTtv=[]
  months.forEach(({y,m})=>{
    const s=`${y}-${String(m).padStart(2,'0')}-01`
    const lastD=new Date(Date.UTC(y,m,0)).getUTCDate()
    const e=`${y}-${String(m).padStart(2,'0')}-${String(lastD).padStart(2,'0')}`
    const sm=sumSOD(s,e)
    netB.push(sm.b-sm.c); netTtv.push(sm.tn)
  })

  // Scale excludes backfill months
  const normalNet=netB.filter((_,i)=>!isBackfill(months[i].y,months[i].m))
  const maxNet=Math.max(...normalNet)*1.15||1
  const maxTtv=Math.max(...netTtv.filter((_,i)=>!isBackfill(months[i].y,months[i].m)))*1.25||1
  const netStep=niceStep(maxNet/4), ttvStep=niceStep(maxTtv/4)
  const groupW=plotW/n, barW=Math.min(groupW*0.72,38)

  const elems=[]
  // Grid
  for(let i=0;i<=4;i++){
    const y=PAD.t+plotH-(i/4)*plotH
    elems.push(<line key={'g'+i} x1={PAD.l} y1={y} x2={W-PAD.r} y2={y} stroke={T.line} strokeWidth={0.7}/>)
    elems.push(<text key={'yl'+i} x={PAD.l-6} y={y+3.5} textAnchor="end" fontSize={9} fill={T.inkSoft}>{fmtNum(Math.round(netStep*i))}</text>)
    elems.push(<text key={'yr'+i} x={W-PAD.r+6} y={y+3.5} textAnchor="start" fontSize={9} fill={T.amber}>{fmtGBP(Math.round(ttvStep*i))}</text>)
  }

  // Bars
  months.forEach(({y,m},i)=>{
    const cx=PAD.l+i*groupW+groupW/2, x=cx-barW/2
    const bf=isBackfill(y,m), cur=isCurrent(y,m)
    const v=netB[i]
    let bh, fill, opacity=1
    if(bf){
      bh=Math.min((v/maxNet)*plotH,plotH)
      fill=T.salmon; opacity=m===3?1:0.88
    } else {
      bh=Math.min((v/maxNet)*plotH,plotH)
      fill=T.pine; opacity=cur?0.45:1
    }
    const ry=PAD.t+plotH-bh
    elems.push(
      <rect key={'bar'+i} x={x} y={ry} width={barW} height={bh} rx={2} fill={fill} opacity={opacity}>
        <title>{y}-{String(m).padStart(2,'0')}: net={fmtNum(v)}, TTV={fmtGBP(netTtv[i])}</title>
      </rect>
    )
    // Feb 2025 backfill label
    if(m===2&&y===2025){
      elems.push(<text key="bfl" x={cx} y={ry-4} textAnchor="middle" fontSize={8} fontWeight={600} fill={T.coral}>backfill</text>)
    }
    // Mar 2025 — clipped, print value + zigzag
    if(m===3&&y===2025){
      const zby=ry+12
      elems.push(<polyline key="zig" points={`${x},${zby} ${x+barW*0.25},${zby-5} ${x+barW*0.5},${zby+5} ${x+barW*0.75},${zby-5} ${x+barW},${zby}`} fill="none" stroke="white" strokeWidth={1.5}/>)
      elems.push(<text key="marval" x={cx} y={ry-4} textAnchor="middle" fontSize={9} fontWeight={700} fill={T.coral}>{fmtNum(v)}</text>)
    }
    // Jul 2026 to-date
    if(cur){
      elems.push(<text key="cur" x={cx} y={ry-4} textAnchor="middle" fontSize={8} fill={T.inkSoft}>to-date</text>)
    }
  })

  // TTV line (skip backfill)
  const ttvPts=months.map(({y,m},i)=>({
    x:PAD.l+i*groupW+groupW/2,
    y:PAD.t+plotH-(netTtv[i]/maxTtv)*plotH,
    skip:isBackfill(y,m)
  }))
  let pathD=''
  ttvPts.forEach(p=>{ if(p.skip){ pathD+=''; return }; pathD+=(pathD===''||pathD.slice(-1)==='Z'?'M':'L')+p.x.toFixed(1)+','+p.y.toFixed(1)+' ' })
  if(pathD) elems.push(<path key="ttvline" d={pathD} fill="none" stroke={T.amber} strokeWidth={1.8} strokeLinejoin="round"/>)

  // TTV points
  ttvPts.forEach((p,i)=>{
    if(p.skip) return
    const {y,m}=months[i]
    elems.push(<circle key={'tp'+i} cx={p.x.toFixed(1)} cy={p.y.toFixed(1)} r={3} fill={T.amber}><title>{y}-{String(m).padStart(2,'0')}: TTV={fmtGBP(netTtv[i])}</title></circle>)
  })

  // X labels
  months.forEach(({y,m},i)=>{
    const cx=PAD.l+i*groupW+groupW/2
    const mo=['','Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][m]
    const lbl=m===1?`${mo} '${String(y).slice(2)}`:mo
    elems.push(<text key={'xl'+i} x={cx.toFixed(1)} y={H-PAD.b+14} textAnchor="middle" fontSize={9} fill={T.inkSoft}>{lbl}</text>)
  })

  return (
    <svg width={W} height={H} style={{display:'block',fontFamily:"'DM Sans',system-ui,sans-serif"}}>
      {elems}
    </svg>
  )
}

// ─── Site-wide funnel from daily SD ─────────────────────────────────────────
// Returns {s, vs, pf, p, tx, r} summed over the GA4-valid portion of [f..t]
function siteGa4Range(f, t) {
  const lo = Math.max(f, GA4_START), hi = Math.min(t, GA4_END)
  let s=0,vs=0,pf=0,p=0,tx=0,r=0
  if (lo > hi) return {s:0,vs:0,pf:0,p:0,tx:0,r:0}
  for (let o=lo; o<=hi; o++) {
    const d=SD[o]; if(!d) continue
    s+=d[0]; vs+=d[1]; pf+=d[2]; p+=d[3]; tx+=d[4]; r+=d[5]
  }
  return {s,vs,pf,p,tx,r}
}

