  const aov = cur.tx>0 ? Math.round(cur.r/cur.tx) : 0
  const cancRateCur = curOps.b>0 ? (curOps.c/curOps.b*100).toFixed(1) : '0.0'
  const cancRatePrv = (prvOps&&prvOps.b>0) ? (prvOps.c/prvOps.b*100).toFixed(1) : null

